import { showError } from '@nextcloud/dialogs';
import { loadState } from '@nextcloud/initial-state';
import { t } from '@nextcloud/l10n';
import NcButton from '@nextcloud/vue/components/NcButton';
import NcCheckboxRadioSwitch from '@nextcloud/vue/components/NcCheckboxRadioSwitch';
import NcInputField from '@nextcloud/vue/components/NcInputField';
import NcLoadingIcon from '@nextcloud/vue/components/NcLoadingIcon';
import NcModal from '@nextcloud/vue/components/NcModal';
import NcNoteCard from '@nextcloud/vue/components/NcNoteCard';
import NcSettingsSection from '@nextcloud/vue/components/NcSettingsSection';
import NcTextArea from '@nextcloud/vue/components/NcTextArea';
import PencilIcon from 'vue-material-design-icons/PencilOutline.vue';
import PlusIcon from 'vue-material-design-icons/Plus.vue';
import BruteForceItem from './components/BruteForceItem.vue';
import { addWhitelist, deleteWhitelist, getWhitelist } from './services/bruteforceSettingsServices.js';
const COMMENT_MAX_LENGTH = 1000;
export default {
  name: 'App',
  components: {
    BruteForceItem,
    NcButton,
    NcNoteCard,
    NcSettingsSection,
    NcCheckboxRadioSwitch,
    NcInputField,
    NcTextArea,
    PencilIcon,
    PlusIcon,
    NcModal,
    NcLoadingIcon
  },
  data() {
    return {
      items: [],
      newWhitelist: {
        ip: '',
        mask: '',
        comment: ''
      },
      remoteAddress: '',
      delay: 0,
      isBypassListed: false,
      isApplyAllowListToRateLimitEnabled: false,
      loadingRateLimit: false,
      loadingEdit: false,
      openEditDialog: false,
      editingItem: null,
      hasExceededTextLimit: false,
      helperText: t('bruteforcesettings', 'The comment cannot exceed {max} characters.', {
        max: COMMENT_MAX_LENGTH
      }),
      commentHint: t('bruteforcesettings', 'Leave an internal comment explaining why this IP address is allowed, for example its location, so the entry can be removed when it is no longer needed.')
    };
  },
  computed: {
    sortedItems() {
      return [...this.items].sort((a, b) => {
        return a.ip.localeCompare(b.ip);
      });
    },
    noteCardText() {
      if (this.delay) {
        return t('bruteforcesettings', 'Your current IP address is detected as "{remoteAddress}". This address is currently throttled. Current delay: {delay} ms.', {
          remoteAddress: this.remoteAddress,
          delay: this.delay
        });
      }
      if (this.isBypassListed) {
        return t('bruteforcesettings', 'Your current IP address is detected as "{remoteAddress}". This address bypasses brute-force protection.', {
          remoteAddress: this.remoteAddress
        });
      }
      return t('bruteforcesettings', 'Your current IP address is detected as "{remoteAddress}". This address is not currently throttled.', {
        remoteAddress: this.remoteAddress
      });
    },
    noteCardLevel() {
      if (this.delay) {
        return 'error';
      }
      if (this.isBypassListed) {
        return 'warning';
      }
      return 'success';
    },
    disabled() {
      return !this.newWhitelist.ip.length || !this.newWhitelist.mask.length;
    }
  },
  beforeMount() {
    this.remoteAddress = loadState('bruteforcesettings', 'remote-address', '127.0.0.1');
    this.isBypassListed = loadState('bruteforcesettings', 'bypass-listed', false);
    this.delay = loadState('bruteforcesettings', 'delay', 0);
    this.isApplyAllowListToRateLimitEnabled = loadState('bruteforcesettings', 'apply_allowlist_to_ratelimit', false);
    this.loadWhitelist();
  },
  methods: {
    t,
    async loadWhitelist() {
      const response = await getWhitelist();
      this.items = response.data;
    },
    async deleteWhitelist(id) {
      await deleteWhitelist(id);
      this.items = this.items.filter(item => item.id !== id);
    },
    async addWhitelist() {
      this.hasExceededTextLimit = this.newWhitelist?.comment && this.newWhitelist?.comment?.length > COMMENT_MAX_LENGTH;
      if (this.hasExceededTextLimit) {
        return;
      }
      try {
        const response = await addWhitelist(this.newWhitelist);
        this.items.push(response.data);
        this.newWhitelist.ip = '';
        this.newWhitelist.mask = '';
        this.newWhitelist.comment = '';
      } catch {
        showError(t('bruteforcesettings', 'Failed to add the IP address to the allow list.'));
      }
    },
    saveApplyAllowListToRateLimit(value) {
      if (this.loadingRateLimit) {
        return;
      }
      this.loadingRateLimit = true;
      OCP.AppConfig.setValue('bruteforcesettings', 'apply_allowlist_to_ratelimit', value ? '1' : '0', {
        success: () => {
          this.loadingRateLimit = false;
          this.isApplyAllowListToRateLimitEnabled = value;
        },
        error: () => {
          this.loadingRateLimit = false;
          showError(t('bruteforcesettings', 'Failed to save the rate limit setting.'));
        }
      });
    },
    editWhitelist(item) {
      this.openEditDialog = true;
      this.editingItem = {
        ...item
      };
      this.hasExceededTextLimit = false;
    },
    async saveEdit() {
      this.hasExceededTextLimit = this.editingItem?.comment && this.editingItem?.comment?.length > COMMENT_MAX_LENGTH;
      if (this.hasExceededTextLimit) {
        return;
      }
      this.loadingEdit = true;
      try {
        const response = await addWhitelist(this.editingItem);
        this.clearEditing();
        // Update the item in the list
        const index = this.items.findIndex(i => i.id === response.data.id);
        if (index !== -1) {
          this.items.splice(index, 1, response.data);
        }
      } catch {
        showError(t('bruteforcesettings', 'Failed to update the allow list entry.'));
      } finally {
        this.loadingEdit = false;
      }
    },
    clearEditing() {
      this.openEditDialog = false;
      this.editingItem = null;
      this.hasExceededTextLimit = false;
    }
  }
};